using System.IO;
using System.Text.Json;
using Xunit;
using Xunit.Abstractions;
using Fhir.Resource.Tests.Common;
using Fhir.TypeFramework.DataTypes;
using Fhir.TypeFramework.DataTypes.PrimitiveTypes;
using Fhir.Resources.R5;

namespace Fhir.Resources.R5.Tests;

public class CapabilityStatementSerializationTests
{
    private readonly ITestOutputHelper _output;

    public CapabilityStatementSerializationTests(ITestOutputHelper output) => _output = output;

    public static IEnumerable<object[]> OfficialExampleRelativePaths =>
        new object[][]
        {
            new object[] { "CapabilityStatement.example.json" },
            new object[] { "CapabilityStatement.example.2.json" },
            new object[] { "CapabilityStatement.example.3.json" },
            new object[] { "CapabilityStatement.example.4.json" },
            new object[] { "CapabilityStatement.example.5.json" },
        };

    [Theory]
    [MemberData(nameof(OfficialExampleRelativePaths))]
    public void Deserialize_official_fixtures_then_roundtrip_and_assert_id(string relativePath)
    {
        var path = Path.Combine(AppContext.BaseDirectory, "TestData", relativePath);
        Assert.True(File.Exists(path), "Fixture missing: " + path);
        var json = File.ReadAllText(path);
        _output.WriteLine("=== Fixture JSON ===");
        _output.WriteLine(json);
        string? expectedId = null;
        using (var jd = JsonDocument.Parse(json))
        {
            if (jd.RootElement.TryGetProperty("id", out var idEl) && idEl.ValueKind == JsonValueKind.String)
                expectedId = idEl.GetString();
        }
        var r = FhirJsonRoundTrip.Deserialize<CapabilityStatement>(json);
        Assert.NotNull(r);
        if (expectedId is not null)
            Assert.Equal(expectedId, (string?)r!.Id);
        var back = FhirJsonRoundTrip.Serialize(r!);
        _output.WriteLine("=== Round-trip JSON ===");
        _output.WriteLine(back);
        Assert.Contains("\"resourceType\"", back);
    }

    [Fact]
    public void Serialize_constructed_instance_including_required_primitives()
    {
        var r = new CapabilityStatement
        {
            Id = new FhirId("tc-CapabilityStatement-id"),
            Status = new FhirCode("final"),
            Date = new FhirDateTime("2020-01-01T12:00:00Z"),
            Kind = new FhirCode("test"),
            FhirVersion = new FhirCode("test"),
        };
        var json = FhirJsonRoundTrip.Serialize(r);
        _output.WriteLine("=== Constructed instance JSON ===");
        _output.WriteLine(json);
        Assert.Contains("\"resourceType\"", json);
        Assert.Contains("\"CapabilityStatement\"", json);
    }
}

